%% analyze_test_42_external_validation_mixedness_corrector.m
% Test 42: external validation of k-Wave-trained mixedness log-k correctors.
%
% This test freezes the latest clean-q models and trains only a residual
% mixedness-aware log-k corrector on the k-Wave/Test40 table. The corrector is
% then applied to the OOD simulation predictions generated by Test39.
%
% Important:
%   - Base q models are never retrained here.
%   - Corrector training labels use k-Wave true SWS from Test40.
%   - External Test39 true SWS is used only for evaluation.
%   - Corrector predictors are restricted to variables available in both
%     k-Wave/Test40 and Test39 external predictions: predicted q/SWS, theory
%     q/SWS, predicted composition/mixedness, M/f0/regime, and model-theory
%     disagreements. No true material side, distance, ROI, patch purity,
%     true SWS, or error variables are used for inference.
%
% Runtime controls:
%   ADAPTIVE_REQ_TEST42_MODE               = quick | medium | full
%   ADAPTIVE_REQ_TEST42_TEST39_SOURCE      = quick | medium | full
%   ADAPTIVE_REQ_TEST42_VALIDATE_ONLY      = true | false
%   ADAPTIVE_REQ_TEST42_SAVE_ALL_MAPS      = true | false
%   ADAPTIVE_REQ_TEST42_MAX_MAP_CONDITIONS = integer or Inf
%   ADAPTIVE_REQ_TEST42_USE_PARALLEL       = true | false

clear; clc; close all;
format compact;

this_file = mfilename('fullpath');
root_dir = fileparts(fileparts(fileparts(this_file)));
addpath(root_dir);
root_dir = setup_adaptive_req();
adaptive_req.templates.setup_style();
set(groot,'defaultAxesFontSize',8,'defaultTextFontSize',8, ...
    'defaultLegendFontSize',7,'defaultAxesTitleFontSizeMultiplier',1.08);

CFG = default_config();
CFG = setup_parallel_if_requested(CFG);
OUT = make_output_dirs(root_dir, CFG);
write_config_json(CFG, fullfile(OUT.root_dir, 'test42_configuration.json'));
SRC = locate_sources(root_dir, CFG);

fprintf('\nTest 42: external validation of mixedness-corrected latest q models\n');
fprintf('Mode: %s | Test39 source: %s | output: %s\n', ...
    CFG.Mode, CFG.Test39Source, OUT.root_dir);
fprintf('Base models: %s\n', strjoin(CFG.BaseModels, ', '));
fprintf('Parallel training requested: %d\n', CFG.UseParallel);

assert(exist(SRC.test40_csv,'file') == 2, 'Missing Test40 table: %s', SRC.test40_csv);
assert(exist(SRC.test39_csv,'file') == 2, ['Missing Test39 external table: %s\n' ...
    'Run Test39 first for this source mode, then rerun Test42.'], SRC.test39_csv);

T40 = standardize_train_table(readtable(SRC.test40_csv));
T39 = standardize_external_table(readtable(SRC.test39_csv));
fprintf('Loaded Test40 rows: %d | Test39 external rows: %d.\n', height(T40), height(T39));

if CFG.ValidateOnly
    validate_inputs(T40, T39, CFG);
    fprintf('Test 42 validation-only checks passed.\n');
    return;
end

rng(CFG.RandomSeed, 'twister');

%% Train frozen correctors on k-Wave/Test40 and apply to Test39 OOD

parts = {};
model_info = table();
for i = 1:numel(CFG.BaseModels)
    ext_model = CFG.BaseModels(i);
    train_strategy = "T38_" + ext_model;
    Ttr = T40(T40.strategy_name == train_strategy,:);
    Tex = T39(T39.model_name == ext_model,:);
    assert(~isempty(Ttr), 'Missing Test40 strategy: %s', train_strategy);
    assert(~isempty(Tex), 'Missing Test39 model: %s', ext_model);

    fprintf('[%d/%d] Training frozen corrector on k-Wave for %s (%d train patches), applying to %d OOD patches...\n', ...
        i, numel(CFG.BaseModels), ext_model, height(Ttr), height(Tex));
    [MODEL, I] = train_corrector(Ttr, ext_model, CFG);
    model_info = concat_tables(model_info, I);

    B = external_baseline_rows(Tex, ext_model);
    [Call, Cgated] = apply_corrector(Tex, MODEL, ext_model, CFG);
    parts{end+1,1} = B; %#ok<AGROW>
    parts{end+1,1} = Call; %#ok<AGROW>
    parts{end+1,1} = Cgated; %#ok<AGROW>
end

T_theory = external_baseline_rows(T39(T39.model_name == "theory_discrete",:), "theory_discrete");
T_theory.model_family = repmat("Test39_theory_reference", height(T_theory), 1);
parts{end+1,1} = T_theory;

T_all = vertcat_compatible(parts{:});

%% Summaries

T_overall = summarize_predictions(T_all, ["model_family","strategy_name"]);
T_by_case = summarize_predictions(T_all, ["strategy_name","case_id"]);
T_by_family = summarize_predictions(T_all, ["strategy_name","case_family"]);
T_by_regime = summarize_predictions(T_all, ["strategy_name","field_regime_ood"]);
T_by_frequency = summarize_predictions(T_all, ["strategy_name","f0"]);
T_by_M = summarize_predictions(T_all, ["strategy_name","M"]);
T_by_purity = summarize_predictions(T_all, ["strategy_name","purity_bin"]);
T_by_material = summarize_predictions(T_all, ["strategy_name","case_family","material_region"]);
T_by_zone = summarize_predictions(T_all, ["strategy_name","case_family","region_zone"]);
T_by_material_zone = summarize_predictions(T_all, ["strategy_name","case_id","material_zone"]);
T_by_freq_region = summarize_predictions(T_all, ["strategy_name","case_family","material_region","f0"]);
T_by_M_region = summarize_predictions(T_all, ["strategy_name","case_family","material_region","M"]);
T_by_distance = summarize_predictions(T_all, ["strategy_name","distance_bin"]);
T_gain = correction_gain_summary(T_all, CFG);
T_fail = top_failure_conditions(summarize_predictions(T_all, ...
    ["strategy_name","condition_key","case_id","case_family","field_regime_ood","f0","M"]), 40);

writetable(T_all, fullfile(OUT.table_dir, 'test42_external_patch_level_results.csv'));
writetable(model_info, fullfile(OUT.table_dir, 'test42_frozen_corrector_training_summary.csv'));
writetable(T_overall, fullfile(OUT.table_dir, 'test42_external_summary_overall.csv'));
writetable(T_by_case, fullfile(OUT.table_dir, 'test42_external_summary_by_case.csv'));
writetable(T_by_family, fullfile(OUT.table_dir, 'test42_external_summary_by_family.csv'));
writetable(T_by_regime, fullfile(OUT.table_dir, 'test42_external_summary_by_regime.csv'));
writetable(T_by_frequency, fullfile(OUT.table_dir, 'test42_external_summary_by_frequency.csv'));
writetable(T_by_M, fullfile(OUT.table_dir, 'test42_external_summary_by_M.csv'));
writetable(T_by_purity, fullfile(OUT.table_dir, 'test42_external_summary_by_purity_bin.csv'));
writetable(T_by_material, fullfile(OUT.table_dir, 'test42_external_summary_by_material_region.csv'));
writetable(T_by_zone, fullfile(OUT.table_dir, 'test42_external_summary_by_region_zone.csv'));
writetable(T_by_material_zone, fullfile(OUT.table_dir, 'test42_external_summary_by_material_zone.csv'));
writetable(T_by_freq_region, fullfile(OUT.table_dir, 'test42_external_summary_by_frequency_region.csv'));
writetable(T_by_M_region, fullfile(OUT.table_dir, 'test42_external_summary_by_M_region.csv'));
writetable(T_by_distance, fullfile(OUT.table_dir, 'test42_external_summary_by_distance.csv'));
writetable(T_gain, fullfile(OUT.table_dir, 'test42_external_correction_gain_summary.csv'));
writetable(T_fail, fullfile(OUT.table_dir, 'test42_external_worst_conditions.csv'));

save(fullfile(OUT.data_dir, 'test42_external_validation_mixedness_corrector.mat'), ...
    'T_all','model_info','T_overall','T_by_case','T_by_family','T_by_regime', ...
    'T_by_frequency','T_by_M','T_by_purity','T_by_material','T_by_zone', ...
    'T_by_material_zone','T_by_freq_region','T_by_M_region','T_by_distance', ...
    'T_gain','T_fail','CFG','SRC','-v7.3');

%% Figures

safe_plot(@() plot_model_ranking(T_overall, OUT), 'model ranking');
safe_plot(@() plot_test33_style_diagnostics(T_by_material, T_by_material_zone, ...
    T_by_freq_region, T_by_M_region, CFG, OUT), 'Test33-style diagnostics');
safe_plot(@() plot_heatmap_table(T_by_case, "case_id", OUT, 'test42_mape_by_case.png'), 'case heatmap');
safe_plot(@() plot_heatmap_table(T_by_regime, "field_regime_ood", OUT, 'test42_mape_by_regime.png'), 'regime heatmap');
safe_plot(@() plot_heatmap_table(T_by_frequency, "f0", OUT, 'test42_mape_by_frequency.png'), 'frequency heatmap');
safe_plot(@() plot_heatmap_table(T_by_M, "M", OUT, 'test42_mape_by_M.png'), 'M heatmap');
safe_plot(@() plot_distance_curves(T_by_distance, OUT), 'distance curves');
safe_plot(@() plot_correction_gain(T_gain, OUT), 'correction gain');
safe_plot(@() plot_purity_response(T_by_purity, OUT), 'purity response');
if CFG.SaveAllMaps
    safe_plot(@() plot_condition_maps(T_all, CFG, OUT), 'condition maps');
end

print_interpretation(T_overall, T_by_material, T_by_zone, T_gain, T_fail);
fprintf('\nTables: %s\nFigures: %s\nTest 42 complete.\n', OUT.table_dir, OUT.figure_dir);

%% Configuration and loading

function CFG = default_config()
mode = lower(strtrim(string(getenv('ADAPTIVE_REQ_TEST42_MODE'))));
if mode == "", mode = "quick"; end
assert(ismember(mode, ["quick","medium","full"]), ...
    'ADAPTIVE_REQ_TEST42_MODE must be quick, medium, or full.');
src = lower(strtrim(string(getenv('ADAPTIVE_REQ_TEST42_TEST39_SOURCE'))));
if src == "", src = mode; end
assert(ismember(src, ["quick","medium","full"]), ...
    'ADAPTIVE_REQ_TEST42_TEST39_SOURCE must be quick, medium, or full.');

CFG = struct();
CFG.Mode = mode;
CFG.QuickMode = mode == "quick";
CFG.MediumMode = mode == "medium";
CFG.FullMode = mode == "full";
CFG.Test39Source = src;
CFG.ValidateOnly = env_true('ADAPTIVE_REQ_TEST42_VALIDATE_ONLY', false);
CFG.SaveAllMaps = env_true('ADAPTIVE_REQ_TEST42_SAVE_ALL_MAPS', true);
CFG.MaxMapConditions = env_number('ADAPTIVE_REQ_TEST42_MAX_MAP_CONDITIONS', ternary(mode=="quick", 4, 24));
CFG.UseParallel = env_true('ADAPTIVE_REQ_TEST42_USE_PARALLEL', false);
CFG.RandomSeed = 42001;
CFG.NumLearningCycles = env_number('ADAPTIVE_REQ_TEST42_NUM_TREES', ternary(mode=="quick", 100, 180));
CFG.MinLeafSize = env_number('ADAPTIVE_REQ_TEST42_MIN_LEAF_SIZE', 80);
CFG.PhysicalRange = [0.5 10];
if CFG.QuickMode
    CFG.BaseModels = ["q_spectrum_plus_composition","q_spectrum_only"];
else
    CFG.BaseModels = ["q_spectrum_plus_composition","q_spectrum_plus_theory_composition", ...
        "q_spectrum_only","delta_q_theory_composition"];
end
CFG.PlotStrategies = ["theory_discrete", ...
    "q_spectrum_plus_composition", ...
    "T42_q_spectrum_plus_composition_logk_all", ...
    "T42_q_spectrum_plus_composition_logk_mixed_gated", ...
    "q_spectrum_only", ...
    "T42_q_spectrum_only_logk_all", ...
    "T42_q_spectrum_only_logk_mixed_gated"];
end

function CFG = setup_parallel_if_requested(CFG)
if ~CFG.UseParallel
    CFG.StatOptions = statset('UseParallel', false);
    CFG.LSBoostOptions = statset('UseParallel', false);
    return;
end
try
    pool = gcp('nocreate');
    if isempty(pool)
        parpool('threads');
    end
    CFG.StatOptions = statset('UseParallel', true);
    % MATLAB only parallelizes Bag ensembles. The residual regressor uses
    % LSBoost, so keep that fit serial even when a pool is available.
    CFG.LSBoostOptions = statset('UseParallel', false);
catch ME
    warning('Could not start/use parallel pool (%s). Continuing serial.', ME.message);
    CFG.UseParallel = false;
    CFG.StatOptions = statset('UseParallel', false);
    CFG.LSBoostOptions = statset('UseParallel', false);
end
end

function OUT = make_output_dirs(root_dir, CFG)
OUT.root_dir = fullfile(root_dir, 'outputs', 'test_42_external_validation_mixedness_corrector');
if CFG.QuickMode
    OUT.root_dir = fullfile(OUT.root_dir, 'quick');
elseif CFG.MediumMode
    OUT.root_dir = fullfile(OUT.root_dir, 'medium');
end
OUT.table_dir = fullfile(OUT.root_dir, 'tables');
OUT.figure_dir = fullfile(OUT.root_dir, 'figures');
OUT.map_dir = fullfile(OUT.figure_dir, 'maps_by_condition');
OUT.data_dir = fullfile(OUT.root_dir, 'data');
for d = string(struct2cell(OUT))'
    if exist(d,'dir') ~= 7, mkdir(d); end
end
end

function SRC = locate_sources(root_dir, CFG)
SRC = struct();
SRC.test40_csv = fullfile(root_dir, 'outputs', 'test_40_kwave_latest_model_comparison', ...
    'tables', 'test40_kwave_patch_level_model_comparison.csv');
base39 = fullfile(root_dir, 'outputs', 'test_39_frozen_test38_external_validation');
if CFG.Test39Source == "quick"
    SRC.test39_csv = fullfile(base39, 'quick', 'tables', 'test39_external_patch_level_predictions.csv');
elseif CFG.Test39Source == "medium"
    SRC.test39_csv = fullfile(base39, 'medium', 'tables', 'test39_external_patch_level_predictions.csv');
else
    SRC.test39_csv = fullfile(base39, 'tables', 'test39_external_patch_level_predictions.csv');
end
end

function validate_inputs(T40, T39, CFG)
need40 = ["condition_key","strategy_name","M","f0","field_regime","q_pred","sws_pred", ...
    "true_SWS","predicted_patch_purity","p_mixed","sws_theory_ref"];
need39 = ["condition_key","model_name","M","f0","field_regime_ood","q_pred","sws_pred", ...
    "true_SWS","predicted_patch_purity","p_mixed","sws_theory"];
assert(all(ismember(need40, string(T40.Properties.VariableNames))), ...
    'Test40 train table missing required variables.');
assert(all(ismember(need39, string(T39.Properties.VariableNames))), ...
    'Test39 external table missing required variables.');
for m = CFG.BaseModels
    assert(any(T40.strategy_name == "T38_" + m), 'Missing Test40 train model T38_%s.', m);
    assert(any(T39.model_name == m), 'Missing Test39 external model %s.', m);
end
assert_no_oracle_features(operational_feature_names());
end

function T = standardize_train_table(T)
T = convert_strings(T);
T.field_regime_ood = T.field_regime;
T.sws_theory_ref = lookup_strategy(T, "T34_theory_baseline");
T.q_theory_ref = nan(height(T),1);
idx = T.strategy_name == "T34_theory_baseline";
theory_keys = T.patch_key(idx);
theory_q = T.q_pred(idx);
[ok,loc] = ismember(T.patch_key, theory_keys);
T.q_theory_ref(ok) = theory_q(loc(ok));
T.q_theory_ref(~isfinite(T.q_theory_ref)) = 0.5;
if ~ismember("p_strong_mixed", string(T.Properties.VariableNames))
    T.p_strong_mixed = zeros(height(T),1);
end
end

function T = standardize_external_table(T)
T = convert_strings(T);
T.strategy_name = T.model_name;
T.model_family = repmat("Test39_external_baseline", height(T), 1);
T.sws_theory_ref = T.sws_theory;
T.q_theory_ref = T.q_theory_prior;
if ~ismember("p_strong_mixed", string(T.Properties.VariableNames))
    T.p_strong_mixed = zeros(height(T),1);
end
T.patch_key = T.condition_key + "__iz" + string(T.map_iz) + "__ix" + string(T.map_ix);
end

function T = convert_strings(T)
vars = string(T.Properties.VariableNames);
for v = ["condition_key","case_id","case_family","field_regime","field_regime_ood", ...
        "purity_bin","distance_bin","material_region","region_zone","material_zone", ...
        "model_name","model_family","strategy_name","geometry","geometry_type"]
    if ismember(v, vars)
        T.(v) = string(T.(v));
    end
end
if ~ismember("patch_key", vars) && all(ismember(["condition_key","map_iz","map_ix"], vars))
    T.patch_key = T.condition_key + "__iz" + string(T.map_iz) + "__ix" + string(T.map_ix);
end
end

function y = lookup_strategy(T, strategy)
R = T(T.strategy_name == strategy, {'patch_key','sws_pred'});
[ok,loc] = ismember(T.patch_key, R.patch_key);
y = nan(height(T),1);
y(ok) = R.sws_pred(loc(ok));
end

%% Corrector training/application

function [MODEL, info] = train_corrector(T, model_name, CFG)
[X, names] = build_features(T);
assert_no_oracle_features(names);
valid = all(isfinite(X),2) & isfinite(T.sws_pred) & T.sws_pred > 0 & ...
    isfinite(T.true_SWS) & T.true_SWS > 0;
base_k = 2*pi*T.f0 ./ T.sws_pred;
true_k = 2*pi*T.f0 ./ T.true_SWS;
target = log(true_k) - log(base_k);
tree = templateTree('MinLeafSize', CFG.MinLeafSize, 'MaxNumSplits', 384);
mdl = fitrensemble(X(valid,:), target(valid), ...
    'Method','LSBoost','Learners',tree,'NumLearningCycles',CFG.NumLearningCycles, ...
    'LearnRate',0.05,'Options',CFG.LSBoostOptions);
MODEL = struct();
MODEL.model = mdl;
MODEL.feature_names = names;
MODEL.model_name = model_name;
pred = predict(MODEL.model, X(valid,:));
info = table(model_name, nnz(valid), mean(abs(target(valid)),'omitnan'), ...
    mean(abs(pred-target(valid)),'omitnan'), CFG.NumLearningCycles, CFG.MinLeafSize, ...
    'VariableNames', {'model_name','N_train','mean_abs_delta_logk_label', ...
    'train_mean_abs_delta_logk_residual','num_learning_cycles','min_leaf_size'});
end

function [Call, Cgated] = apply_corrector(T, MODEL, model_name, CFG)
[X, names] = build_features(T);
assert(isequal(string(MODEL.feature_names(:)), string(names(:))), ...
    'Corrector feature mismatch.');
delta = predict(MODEL.model, X);
base_logk = log(2*pi*T.f0 ./ T.sws_pred);
gate = mixedness_gate(T);
sws_all = clip_sws(2*pi*T.f0 ./ exp(base_logk + delta), CFG);
sws_gated = clip_sws(2*pi*T.f0 ./ exp(base_logk + gate.*delta), CFG);
Call = corrected_rows(T, model_name, "logk_all", sws_all, delta, ones(height(T),1), CFG);
Cgated = corrected_rows(T, model_name, "logk_mixed_gated", sws_gated, delta, gate, CFG);
end

function [X, names] = build_features(T)
names = operational_feature_names();
q = fill_default(T.q_pred, 0.5);
q_theory = fill_default(T.q_theory_ref, 0.5);
purity = fill_default(T.predicted_patch_purity, 0.95);
p_mixed = fill_default(T.p_mixed, 1-purity);
p_strong = fill_default(T.p_strong_mixed, 0);
theory = fill_default(T.sws_theory_ref, T.sws_pred);
reg = regime_code(T);
X = [ ...
    normalize_like(T.M, 3, 1), ...
    normalize_like(T.f0, 500, 150), ...
    reg, ...
    purity, ...
    1-purity, ...
    p_mixed, ...
    p_strong, ...
    log(max(T.sws_pred, 0.1)), ...
    q, ...
    log(max(theory, 0.1)), ...
    q_theory, ...
    log(max(T.sws_pred, 0.1)) - log(max(theory, 0.1)), ...
    q - q_theory, ...
    abs(T.sws_pred - theory)./max(theory,0.25) ...
    ];
X = double(X);
X(~isfinite(X)) = 0;
end

function names = operational_feature_names()
names = ["M_norm","f0_norm","field_regime_code", ...
    "predicted_patch_purity","predicted_impurity","p_mixed","p_strong_mixed", ...
    "log_sws_base","q_pred","log_sws_theory_ref","q_theory_ref", ...
    "log_base_minus_theory","q_minus_theory","rel_base_theory_disagreement"];
end

function assert_no_oracle_features(names)
bad = ["true","oracle","material","side","roi","distance", ...
    "error","signed","abs_error","high_error","cs_true","sws_true","k_true"];
for b = bad
    hit = names(contains(lower(names), b));
    assert(isempty(hit), 'Oracle/evaluation feature leaked into Test42 corrector: %s', strjoin(hit, ', '));
end
end

function gate = mixedness_gate(T)
purity = fill_default(T.predicted_patch_purity, 0.95);
p = fill_default(T.p_mixed, 1-purity);
ps = fill_default(T.p_strong_mixed, 0);
gate = max([p, 1-purity, 0.75*ps], [], 2);
gate = min(max(gate, 0), 1);
end

function C = corrected_rows(T, model_name, variant, sws, delta, gate, CFG)
C = external_baseline_rows(T, model_name);
C.model_family = repmat("T42_kWave_trained_mixedness_corrector", height(T), 1);
C.base_model_name = repmat(model_name, height(T), 1);
C.correction_variant = repmat(variant, height(T), 1);
C.strategy_name = repmat("T42_" + model_name + "_" + variant, height(T), 1);
C.sws_pred = sws;
C.sws_signed_error_pct = 100*(sws - C.true_SWS)./C.true_SWS;
C.sws_abs_error_pct = abs(C.sws_signed_error_pct);
C.high_error10 = C.sws_abs_error_pct > 10;
C.high_error20 = C.sws_abs_error_pct > 20;
C.delta_logk_pred = delta;
C.mixedness_gate = gate;
C.sws_pred = clip_sws(C.sws_pred, CFG);
end

function B = external_baseline_rows(T, model_name)
B = T;
B.model_family = repmat("Test39_external_baseline", height(T), 1);
B.base_model_name = repmat(model_name, height(T), 1);
B.correction_variant = repmat("none", height(T), 1);
B.strategy_name = repmat(model_name, height(T), 1);
B.delta_logk_pred = nan(height(T),1);
B.mixedness_gate = zeros(height(T),1);
end

%% Summaries

function S = summarize_predictions(T, group_vars)
if isstring(group_vars), group_vars = cellstr(group_vars); end
[G, groups] = findgroups(T(:, group_vars));
n = splitapply(@numel, T.sws_abs_error_pct, G);
mape = splitapply(@(x) mean(x,'omitnan'), T.sws_abs_error_pct, G);
medae = splitapply(@(x) median(x,'omitnan'), T.sws_abs_error_pct, G);
signed = splitapply(@(x) mean(x,'omitnan'), T.sws_signed_error_pct, G);
medsigned = splitapply(@(x) median(x,'omitnan'), T.sws_signed_error_pct, G);
under = splitapply(@(x) 100*mean(x < 0,'omitnan'), T.sws_signed_error_pct, G);
he10 = splitapply(@(x) 100*mean(x,'omitnan'), T.high_error10, G);
he20 = splitapply(@(x) 100*mean(x,'omitnan'), T.high_error20, G);
mean_sws = splitapply(@(x) mean(x,'omitnan'), T.sws_pred, G);
mean_purity = splitapply(@(x) mean(x,'omitnan'), T.predicted_patch_purity, G);
mean_mixed = splitapply(@(x) mean(x,'omitnan'), T.p_mixed, G);
S = [groups table(n,mape,medae,signed,medsigned,under,he10,he20,mean_sws,mean_purity,mean_mixed, ...
    'VariableNames', {'N','MAPE_pct','median_abs_error_pct','mean_signed_error_pct', ...
    'median_signed_error_pct','underestimate_pct','high_error10_pct','high_error20_pct', ...
    'mean_sws_pred','mean_predicted_patch_purity','mean_p_mixed'})];
end

function T = correction_gain_summary(P, CFG)
T = table();
for base = CFG.BaseModels(:)'
    B = P(P.strategy_name == base,:);
    for variant = ["logk_all","logk_mixed_gated"]
        s = "T42_" + base + "_" + variant;
        C = P(P.strategy_name == s,:);
        if isempty(B) || isempty(C), continue; end
        [ok,loc] = ismember(C.patch_key, B.patch_key);
        gain = B.sws_abs_error_pct(loc(ok)) - C.sws_abs_error_pct(ok);
        R = C(ok, {'strategy_name','case_family','material_region','region_zone','purity_bin'});
        R.mape_gain_points = gain;
        T = concat_tables(T, R);
    end
end
if isempty(T), return; end
T = summarize_gain(T, ["strategy_name","case_family","material_region","region_zone","purity_bin"]);
end

function S = summarize_gain(T, group_vars)
[G, groups] = findgroups(T(:, cellstr(group_vars)));
n = splitapply(@numel, T.mape_gain_points, G);
gain = splitapply(@(x) mean(x,'omitnan'), T.mape_gain_points, G);
frac = splitapply(@(x) 100*mean(x > 0,'omitnan'), T.mape_gain_points, G);
S = [groups table(n,gain,frac, 'VariableNames', {'N','mean_mape_gain_points','pct_pixels_improved'})];
end

function T = top_failure_conditions(T, n)
T = sortrows(T, {'MAPE_pct','high_error20_pct'}, {'descend','descend'});
T = T(1:min(n,height(T)),:);
end

