function plot_condition_maps(T, CFG, OUT)
keep = select_plot_strategies(T.strategy_name, CFG);
conds = unique(T(:, {'case_id','field_regime_ood','f0','M'}), 'rows', 'stable');
if isfinite(CFG.MaxMapConditions) && height(conds) > CFG.MaxMapConditions
    conds = conds(1:CFG.MaxMapConditions,:);
end
fprintf('Saving %d Test42 external map panels under %s.\n', height(conds), OUT.map_dir);
for ci = 1:height(conds)
    idx = T.case_id == conds.case_id(ci) & T.field_regime_ood == conds.field_regime_ood(ci) & ...
        T.f0 == conds.f0(ci) & T.M == conds.M(ci);
    Xc = T(idx,:);
    if isempty(Xc), continue; end
    base = Xc(Xc.strategy_name == Xc.strategy_name(1),:);
    [true_map,nz,nx] = rows_to_grid(base, base.true_SWS);
    fig = figure('Color','w','Units','centimeters','Position',[1 1 36 24]);
    tl = tiledlayout(fig,4,4,'TileSpacing','compact','Padding','compact');
    plot_map(nexttile(tl), true_map, 'True SWS');
    plot_map(nexttile(tl), rows_to_grid(base, base.predicted_patch_purity, nz, nx), 'Predicted purity');
    plot_map(nexttile(tl), rows_to_grid(base, base.p_mixed, nz, nx), 'P(mixed)');
    plot_map(nexttile(tl), rows_to_grid(base, base.distance_to_boundary_mm, nz, nx), 'Distance mm');
    for si = 1:numel(keep)
        s = keep(si);
        X = Xc(Xc.strategy_name == s,:);
        if isempty(X), continue; end
        plot_map(nexttile(tl), rows_to_grid(X, X.sws_pred, nz, nx), s + ' SWS');
    end
    err_keep = keep(1:min(4,numel(keep)));
    for si = 1:numel(err_keep)
        s = err_keep(si);
        X = Xc(Xc.strategy_name == s,:);
        if isempty(X), continue; end
        plot_map(nexttile(tl), rows_to_grid(X, X.sws_abs_error_pct, nz, nx), s + ' err %');
    end
    title(tl, sprintf('%s | %s | f%d | M%d', conds.case_id(ci), ...
        conds.field_regime_ood(ci), conds.f0(ci), conds.M(ci)), 'Interpreter','none');
    outdir = fullfile(OUT.map_dir, sanitize(conds.case_id(ci)), sanitize(conds.field_regime_ood(ci)), ...
        "f" + string(conds.f0(ci)), "M" + string(conds.M(ci)));
    if exist(outdir,'dir') ~= 7, mkdir(outdir); end
    export_fig(fig, fullfile(outdir, sprintf('test42_map__%s__%s__f%d__M%d.png', ...
        sanitize(conds.case_id(ci)), sanitize(conds.field_regime_ood(ci)), conds.f0(ci), conds.M(ci))));
end
end

function grouped_bar(ax, T, group_var, strategies, metric)
groups = unique(string(T.(group_var)), 'stable');
Y = nan(numel(groups), numel(strategies));
for i = 1:numel(groups)
    for j = 1:numel(strategies)
        idx = string(T.(group_var)) == groups(i) & T.strategy_name == strategies(j);
        if any(idx), Y(i,j) = mean(T.(metric)(idx), 'omitnan'); end
    end
end
bar(ax, categorical(groups), Y);
set(ax,'TickLabelInterpreter','none');
end

function keep = select_plot_strategies(strategies, CFG)
available = unique(string(strategies), 'stable');
preferred = string(CFG.PlotStrategies(:));
keep = preferred(ismember(preferred, available));
if isempty(keep), keep = available(1:min(8,numel(available))); end
end

function print_interpretation(T_overall, Tmat, Tzone, Tgain, Tfail)
T = sortrows(T_overall, 'MAPE_pct', 'ascend');
fprintf('\n================ Test 42 external validation summary ================\n');
disp(T(1:min(14,height(T)), {'model_family','strategy_name','N','MAPE_pct', ...
    'mean_signed_error_pct','high_error20_pct'}));
fprintf('Best external overall: %s (MAPE %.2f%%, signed %.2f%%, HE20 %.2f%%).\n', ...
    T.strategy_name(1), T.MAPE_pct(1), T.mean_signed_error_pct(1), T.high_error20_pct(1));
H = Tmat(ismember(Tmat.material_region, ["hard","inclusion"]),:);
if ~isempty(H)
    Hs = sortrows(summarize_predictions_from_summary(H, "strategy_name"), 'MAPE_pct', 'ascend');
    fprintf('Best hard/inclusion material regions: %s (MAPE %.2f%%).\n', Hs.strategy_name(1), Hs.MAPE_pct(1));
end
I = Tzone(Tzone.region_zone=="interface_0_2mm",:);
if ~isempty(I)
    Is = sortrows(summarize_predictions_from_summary(I, "strategy_name"), 'MAPE_pct', 'ascend');
    fprintf('Best interface zones: %s (MAPE %.2f%%).\n', Is.strategy_name(1), Is.MAPE_pct(1));
end
if ~isempty(Tgain)
    G = sortrows(Tgain, 'mean_mape_gain_points', 'descend');
    fprintf('Largest average correction gain: %s / %s / %s = %.2f points.\n', ...
        G.strategy_name(1), G.material_region(1), G.region_zone(1), G.mean_mape_gain_points(1));
end
fprintf('Worst conditions table saved with %d rows.\n', height(Tfail));
fprintf('=====================================================================\n');
end

function S = summarize_predictions_from_summary(T, group_var)
[G, groups] = findgroups(T(:, cellstr(group_var)));
n = splitapply(@(x) sum(x,'omitnan'), T.N, G);
mape = splitapply(@(m,n) sum(m.*n,'omitnan')/sum(n,'omitnan'), T.MAPE_pct, T.N, G);
signed = splitapply(@(m,n) sum(m.*n,'omitnan')/sum(n,'omitnan'), T.mean_signed_error_pct, T.N, G);
he20 = splitapply(@(m,n) sum(m.*n,'omitnan')/sum(n,'omitnan'), T.high_error20_pct, T.N, G);
S = [groups table(n,mape,signed,he20, 'VariableNames', ...
    {'N','MAPE_pct','mean_signed_error_pct','high_error20_pct'})];
end

%% Utilities

function y = fill_default(x, d)
y = x;
if isscalar(d)
    y(~isfinite(y)) = d;
else
    bad = ~isfinite(y);
    y(bad) = d(bad);
end
end

function y = clip_sws(y, CFG)
y = min(max(y, CFG.PhysicalRange(1)), CFG.PhysicalRange(2));
end

function y = normalize_like(x, mu, sigma)
y = (double(x) - mu) ./ sigma;
end

function code = regime_code(T)
if ismember("field_regime_ood", string(T.Properties.VariableNames))
    r = string(T.field_regime_ood);
else
    r = string(T.field_regime);
end
code = zeros(numel(r),1);
code(contains(r,"directional")) = 1;
code(contains(r,"diffuse_2D")) = 2;
code(contains(r,"partial")) = 3;
code(contains(r,"diffuse_3D")) = 4;
code = normalize_like(code, 2.5, 1.2);
end

function T = vertcat_compatible(varargin)
vars = strings(1,0);
for i = 1:nargin
    vars = [vars string(varargin{i}.Properties.VariableNames)]; %#ok<AGROW>
end
vars = unique(vars, 'stable');
string_vars = ["dataset","condition_key","case_id","case_family","field_regime", ...
    "field_regime_ood","purity_bin","distance_bin","material_region","region_zone", ...
    "material_zone","model_name","model_family","strategy_name","base_model_name", ...
    "correction_variant","patch_key"];
logical_vars = ["is_train_row","is_heldout_row","is_mixed","is_strong_mixed", ...
    "high_error10","high_error20"];
parts = cell(nargin,1);
for i = 1:nargin
    A = varargin{i};
    for v = vars
        if ismember(v, string(A.Properties.VariableNames)), continue; end
        if ismember(v, string_vars)
            A.(v) = repmat("unknown", height(A), 1);
        elseif ismember(v, logical_vars)
            A.(v) = false(height(A), 1);
        else
            A.(v) = nan(height(A), 1);
        end
    end
    parts{i} = A(:, cellstr(vars));
end
T = vertcat(parts{:});
end

function T = concat_tables(T, R)
if isempty(T), T = R; else, T = vertcat_compatible(T, R); end
end

function [Z,nz,nx] = rows_to_grid(T, values, nz, nx)
if nargin < 3
    nz = max(T.map_iz); nx = max(T.map_ix);
end
Z = nan(nz,nx);
Z(sub2ind([nz,nx], T.map_iz, T.map_ix)) = values;
end

function plot_map(ax, Z, ttl)
imagesc(ax, Z); axis(ax,'image'); axis(ax,'off'); colorbar(ax);
title(ax, ttl, 'Interpreter','none','FontWeight','normal','FontSize',7);
end

function export_fig(fig, file)
drawnow;
exportgraphics(fig, file, 'Resolution', 220);
close(fig);
end

function safe_plot(fn, label)
try
    fn();
catch ME
    warning('Skipping plot %s: %s', label, ME.message);
end
end

function s = sanitize(s)
s = regexprep(string(s), '[^A-Za-z0-9_=-]+', '_');
end

function tf = env_true(name, default_value)
v = lower(strtrim(string(getenv(name))));
if v == "", tf = default_value; return; end
tf = ismember(v, ["1","true","yes","y","on"]);
end

function x = env_number(name, default_value)
v = strtrim(string(getenv(name)));
if v == "", x = default_value; return; end
x = str2double(v);
if ~isfinite(x), x = default_value; end
end

function y = ternary(cond, a, b)
if cond, y = a; else, y = b; end
end

function write_config_json(CFG, file)
txt = jsonencode(CFG, PrettyPrint=true);
fid = fopen(file,'w');
assert(fid>0, 'Could not write config: %s', file);
fprintf(fid, '%s\n', txt);
fclose(fid);
end
